    /**
     * Get all of WDSEL's bit fields.
     */
    inline void get_WDSEL(bool &ADC, bool &BUSCTRL, bool &DMA, bool &HSTX,
                          bool &I2C0, bool &I2C1, bool &IO_BANK0,
                          bool &IO_QSPI, bool &JTAG, bool &PADS_BANK0,
                          bool &PADS_QSPI, bool &PIO0, bool &PIO1, bool &PIO2,
                          bool &PLL_SYS, bool &PLL_USB, bool &PWM,
                          bool &SHA256, bool &SPI0, bool &SPI1, bool &SYSCFG,
                          bool &SYSINFO, bool &TBMAN, bool &TIMER0,
                          bool &TIMER1, bool &TRNG, bool &UART0, bool &UART1,
                          bool &USBCTRL) volatile
    {
        uint32_t curr = WDSEL;

        ADC = curr & 1u;
        BUSCTRL = curr & (1u << 1u);
        DMA = curr & (1u << 2u);
        HSTX = curr & (1u << 3u);
        I2C0 = curr & (1u << 4u);
        I2C1 = curr & (1u << 5u);
        IO_BANK0 = curr & (1u << 6u);
        IO_QSPI = curr & (1u << 7u);
        JTAG = curr & (1u << 8u);
        PADS_BANK0 = curr & (1u << 9u);
        PADS_QSPI = curr & (1u << 10u);
        PIO0 = curr & (1u << 11u);
        PIO1 = curr & (1u << 12u);
        PIO2 = curr & (1u << 13u);
        PLL_SYS = curr & (1u << 14u);
        PLL_USB = curr & (1u << 15u);
        PWM = curr & (1u << 16u);
        SHA256 = curr & (1u << 17u);
        SPI0 = curr & (1u << 18u);
        SPI1 = curr & (1u << 19u);
        SYSCFG = curr & (1u << 20u);
        SYSINFO = curr & (1u << 21u);
        TBMAN = curr & (1u << 22u);
        TIMER0 = curr & (1u << 23u);
        TIMER1 = curr & (1u << 24u);
        TRNG = curr & (1u << 25u);
        UART0 = curr & (1u << 26u);
        UART1 = curr & (1u << 27u);
        USBCTRL = curr & (1u << 28u);
    }

    /**
     * Set all of WDSEL's bit fields.
     */
    inline void set_WDSEL(bool ADC, bool BUSCTRL, bool DMA, bool HSTX,
                          bool I2C0, bool I2C1, bool IO_BANK0, bool IO_QSPI,
                          bool JTAG, bool PADS_BANK0, bool PADS_QSPI,
                          bool PIO0, bool PIO1, bool PIO2, bool PLL_SYS,
                          bool PLL_USB, bool PWM, bool SHA256, bool SPI0,
                          bool SPI1, bool SYSCFG, bool SYSINFO, bool TBMAN,
                          bool TIMER0, bool TIMER1, bool TRNG, bool UART0,
                          bool UART1, bool USBCTRL) volatile
    {
        uint32_t curr = WDSEL;

        curr &= ~(0b1u);
        curr |= (ADC & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (BUSCTRL & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (DMA & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (HSTX & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (I2C0 & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (I2C1 & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (IO_BANK0 & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (IO_QSPI & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (JTAG & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (PADS_BANK0 & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (PADS_QSPI & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (PIO0 & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (PIO1 & 0b1u) << 12u;
        curr &= ~(0b1u << 13u);
        curr |= (PIO2 & 0b1u) << 13u;
        curr &= ~(0b1u << 14u);
        curr |= (PLL_SYS & 0b1u) << 14u;
        curr &= ~(0b1u << 15u);
        curr |= (PLL_USB & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (PWM & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (SHA256 & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (SPI0 & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (SPI1 & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (SYSCFG & 0b1u) << 20u;
        curr &= ~(0b1u << 21u);
        curr |= (SYSINFO & 0b1u) << 21u;
        curr &= ~(0b1u << 22u);
        curr |= (TBMAN & 0b1u) << 22u;
        curr &= ~(0b1u << 23u);
        curr |= (TIMER0 & 0b1u) << 23u;
        curr &= ~(0b1u << 24u);
        curr |= (TIMER1 & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (TRNG & 0b1u) << 25u;
        curr &= ~(0b1u << 26u);
        curr |= (UART0 & 0b1u) << 26u;
        curr &= ~(0b1u << 27u);
        curr |= (UART1 & 0b1u) << 27u;
        curr &= ~(0b1u << 28u);
        curr |= (USBCTRL & 0b1u) << 28u;

        WDSEL = curr;
    }

