    /**
     * Get all of RESET_DONE's bit fields.
     */
    inline void get_RESET_DONE(bool &ADC, bool &BUSCTRL, bool &DMA, bool &HSTX,
                               bool &I2C0, bool &I2C1, bool &IO_BANK0,
                               bool &IO_QSPI, bool &JTAG, bool &PADS_BANK0,
                               bool &PADS_QSPI, bool &PIO0, bool &PIO1,
                               bool &PIO2, bool &PLL_SYS, bool &PLL_USB,
                               bool &PWM, bool &SHA256, bool &SPI0, bool &SPI1,
                               bool &SYSCFG, bool &SYSINFO, bool &TBMAN,
                               bool &TIMER0, bool &TIMER1, bool &TRNG,
                               bool &UART0, bool &UART1,
                               bool &USBCTRL) volatile
    {
        uint32_t curr = RESET_DONE;

        ADC = curr & 1u;
        BUSCTRL = curr & (1u << 1u);
        DMA = curr & (1u << 2u);
        HSTX = curr & (1u << 3u);
        I2C0 = curr & (1u << 4u);
        I2C1 = curr & (1u << 5u);
        IO_BANK0 = curr & (1u << 6u);
        IO_QSPI = curr & (1u << 7u);
        JTAG = curr & (1u << 8u);
        PADS_BANK0 = curr & (1u << 9u);
        PADS_QSPI = curr & (1u << 10u);
        PIO0 = curr & (1u << 11u);
        PIO1 = curr & (1u << 12u);
        PIO2 = curr & (1u << 13u);
        PLL_SYS = curr & (1u << 14u);
        PLL_USB = curr & (1u << 15u);
        PWM = curr & (1u << 16u);
        SHA256 = curr & (1u << 17u);
        SPI0 = curr & (1u << 18u);
        SPI1 = curr & (1u << 19u);
        SYSCFG = curr & (1u << 20u);
        SYSINFO = curr & (1u << 21u);
        TBMAN = curr & (1u << 22u);
        TIMER0 = curr & (1u << 23u);
        TIMER1 = curr & (1u << 24u);
        TRNG = curr & (1u << 25u);
        UART0 = curr & (1u << 26u);
        UART1 = curr & (1u << 27u);
        USBCTRL = curr & (1u << 28u);
    }
